export const meta = {
  name: 'deep-codebase-exploration',
  description: '深度并行探索OpenCoreAnalysisKit代码库并生成结构化知识图谱',
  phases: [
    { title: '架构层深度分析', detail: '并行分析11个架构层的实现细节、API接口和关键概念' },
    { title: '跨层关系提取', detail: '分析层间依赖、数据流和调用关系' },
    { title: '知识结构化', detail: '生成知识图谱、API文档和可查询语料库' }
  ]
}

const fs = require('fs');

// 读取已有的分析结果
const layersData = JSON.parse(fs.readFileSync('.understand-anything/intermediate/layers.json', 'utf8'));
const tourData = JSON.parse(fs.readFileSync('.understand-anything/intermediate/tour.json', 'utf8'));
const scanData = JSON.parse(fs.readFileSync('.understand-anything/intermediate/scan-result.json', 'utf8'));

log(`📊 已加载分析结果: ${layersData.length}个架构层, ${tourData.length}步学习路径`);

// 定义深度分析的schema
const LayerAnalysisSchema = {
  type: 'object',
  required: ['layerId', 'coreComponents', 'publicAPIs', 'keyDataStructures', 'dependencies', 'designPatterns', 'criticalPaths'],
  properties: {
    layerId: { type: 'string' },
    layerName: { type: 'string' },
    coreComponents: {
      type: 'array',
      items: {
        type: 'object',
        required: ['name', 'purpose', 'file', 'keyFunctions'],
        properties: {
          name: { type: 'string' },
          purpose: { type: 'string' },
          file: { type: 'string' },
          keyFunctions: { type: 'array', items: { type: 'string' } },
          complexity: { type: 'string', enum: ['low', 'medium', 'high'] }
        }
      }
    },
    publicAPIs: {
      type: 'array',
      items: {
        type: 'object',
        required: ['interface', 'description', 'usageExample'],
        properties: {
          interface: { type: 'string' },
          description: { type: 'string' },
          parameters: { type: 'array', items: { type: 'string' } },
          returnType: { type: 'string' },
          usageExample: { type: 'string' }
        }
      }
    },
    keyDataStructures: {
      type: 'array',
      items: {
        type: 'object',
        required: ['name', 'purpose', 'layout'],
        properties: {
          name: { type: 'string' },
          purpose: { type: 'string' },
          layout: { type: 'string' },
          sizeInfo: { type: 'string' }
        }
      }
    },
    dependencies: {
      type: 'object',
      required: ['dependsOn', 'usedBy'],
      properties: {
        dependsOn: { type: 'array', items: { type: 'string' } },
        usedBy: { type: 'array', items: { type: 'string' } }
      }
    },
    designPatterns: {
      type: 'array',
      items: {
        type: 'object',
        required: ['pattern', 'application', 'benefit'],
        properties: {
          pattern: { type: 'string' },
          application: { type: 'string' },
          benefit: { type: 'string' }
        }
      }
    },
    criticalPaths: {
      type: 'array',
      items: {
        type: 'object',
        required: ['scenario', 'flow', 'files'],
        properties: {
          scenario: { type: 'string' },
          flow: { type: 'string' },
          files: { type: 'array', items: { type: 'string' } }
        }
      }
    }
  }
};

const CrossLayerSchema = {
  type: 'object',
  required: ['interactions', 'dataFlows', 'abstractionBoundaries'],
  properties: {
    interactions: {
      type: 'array',
      items: {
        type: 'object',
        required: ['fromLayer', 'toLayer', 'mechanism', 'frequency'],
        properties: {
          fromLayer: { type: 'string' },
          toLayer: { type: 'string' },
          mechanism: { type: 'string' },
          keyInterfaces: { type: 'array', items: { type: 'string' } },
          frequency: { type: 'string', enum: ['rare', 'common', 'frequent'] }
        }
      }
    },
    dataFlows: {
      type: 'array',
      items: {
        type: 'object',
        required: ['flowName', 'path', 'dataType'],
        properties: {
          flowName: { type: 'string' },
          path: { type: 'array', items: { type: 'string' } },
          dataType: { type: 'string' },
          transformations: { type: 'array', items: { type: 'string' } }
        }
      }
    },
    abstractionBoundaries: {
      type: 'array',
      items: {
        type: 'object',
        required: ['boundary', 'purpose', 'enforcement'],
        properties: {
          boundary: { type: 'string' },
          purpose: { type: 'string' },
          enforcement: { type: 'string' }
        }
      }
    }
  }
};

// Phase 1: 并行深度分析各架构层
phase('架构层深度分析');

log(`🚀 启动${layersData.length}个架构层的并行深度分析...`);

const layerAnalyses = await pipeline(
  layersData,

  // Stage 1: 深度分析每个层
  async (layer, idx) => {
    const fileList = layer.nodeIds
      .filter(id => id.startsWith('file:'))
      .map(id => id.replace('file:', ''))
      .slice(0, 15); // 每层分析前15个核心文件

    const prompt = `深度分析 "${layer.name}" 架构层：

层描述：${layer.description}

核心文件：
${fileList.join('\n')}

请执行以下分析：
1. 识别该层的核心组件及其职责
2. 提取公共API接口和使用模式
3. 分析关键数据结构的内存布局
4. 识别该层依赖的其他层和被哪些层使用
5. 识别使用的设计模式（工厂、观察者、策略等）
6. 提取关键执行路径（如coredump加载、堆遍历、栈回溯）

重点关注：
- 类的继承关系和接口定义
- 函数签名和参数语义
- 数据结构的字段布局和对齐
- 跨层调用的边界和契约

请详细但结构化地分析，提供具体的代码示例。`;

    return await agent(prompt, {
      label: `分析 ${layer.name}`,
      phase: '架构层深度分析',
      schema: LayerAnalysisSchema
    });
  }
);

const validAnalyses = layerAnalyses.filter(Boolean);
log(`✅ 完成${validAnalyses.length}个架构层的深度分析`);

// 保存阶段性结果
fs.writeFileSync('.understand-anything/intermediate/layer-deep-analysis.json', 
  JSON.stringify(validAnalyses, null, 2));

// Phase 2: 跨层关系分析
phase('跨层关系提取');

log(`🔗 分析架构层之间的交互关系...`);

const crossLayerAnalysis = await agent(`基于以下架构层分析结果，提取跨层交互关系：

已分析的层：
${validAnalyses.map(a => `- ${a.layerName}: ${a.coreComponents.length}个核心组件`).join('\n')}

请分析：
1. **层间交互**：哪些层直接调用哪些层？通过什么接口？调用频率如何？
2. **数据流**：数据如何在层之间流动？例如：
   - Coredump文件 → ELF解析 → 内存映射 → ART对象识别 → 命令展示
   - 用户命令 → 命令系统 → Android/Core分析引擎 → 底层API
3. **抽象边界**：各层之间的抽象边界是什么？如何enforced？

重点识别：
- 核心数据流路径（至少5条）
- 高频调用接口
- 关键抽象层（如CoreApi、mirror::Object）

基于具体的代码结构和函数调用分析。`, {
  label: '跨层关系分析',
  phase: '跨层关系提取',
  schema: CrossLayerSchema
});

log(`✅ 识别出${crossLayerAnalysis.interactions.length}个层间交互，${crossLayerAnalysis.dataFlows.length}条数据流`);

fs.writeFileSync('.understand-anything/intermediate/cross-layer-analysis.json',
  JSON.stringify(crossLayerAnalysis, null, 2));

// Phase 3: 知识结构化
phase('知识结构化');

log(`📚 生成结构化知识图谱和文档...`);

// 并行生成多种知识产物
const knowledgeProducts = await parallel([

  // 1. API参考文档
  async () => {
    const apiDoc = await agent(`基于分析结果生成API参考文档：

层分析：${validAnalyses.length}个层
跨层关系：${crossLayerAnalysis.interactions.length}个交互

生成Markdown格式的API参考，包括：
1. **核心API索引** - 按功能分组的所有公共接口
2. **数据结构手册** - 关键数据结构的字段说明
3. **使用模式指南** - 常见任务的代码示例
4. **架构决策记录** - 设计模式和架构权衡

格式要求：
- 使用清晰的标题层次
- 提供代码示例
- 交叉引用相关接口
- 包含复杂度和性能注意事项`, {
      label: 'API文档生成'
    });

    fs.writeFileSync('docs/API-REFERENCE.md', apiDoc);
    return 'API-REFERENCE.md';
  },

  // 2. 数据流图谱
  async () => {
    const dataFlowDoc = await agent(`生成数据流图谱文档：

数据流：
${JSON.stringify(crossLayerAnalysis.dataFlows, null, 2)}

为每条关键数据流生成：
1. **流程图** (Mermaid格式)
2. **涉及的类和函数**
3. **数据转换步骤**
4. **错误处理机制**

重点覆盖：
- Coredump加载流程
- Java堆对象解析流程
- 线程栈回溯流程
- 命令执行流程`, {
      label: '数据流图谱'
    });

    fs.writeFileSync('docs/DATA-FLOWS.md', dataFlowDoc);
    return 'DATA-FLOWS.md';
  },

  // 3. 架构全景图
  async () => {
    const archDoc = await agent(`生成架构全景文档：

架构层：
${layersData.map((l, i) => `${i+1}. ${l.name}: ${l.description}`).join('\n')}

层间依赖：
${JSON.stringify(crossLayerAnalysis.interactions.slice(0, 10), null, 2)}

生成：
1. **架构层次图** (Mermaid图)
2. **各层职责说明**
3. **层间依赖矩阵**
4. **关键设计决策**
5. **扩展点说明**

用Markdown + Mermaid图表展示完整架构。`, {
      label: '架构全景图'
    });

    fs.writeFileSync('docs/ARCHITECTURE-OVERVIEW.md', archDoc);
    return 'ARCHITECTURE-OVERVIEW.md';
  },

  // 4. 开发者指南
  async () => {
    const devGuide = await agent(`生成开发者快速上手指南：

基于：
- 学习路径：${tourData.length}步
- 核心组件分析
- API接口提取

生成指南包括：
1. **5分钟快速开始** - 从零到第一次成功分析coredump
2. **常见任务cookbook** - 添加新命令、解析新数据结构、支持新Android版本
3. **调试技巧** - 常见问题排查
4. **贡献指南** - 代码风格、测试要求、PR流程
5. **架构演进建议** - 已识别的技术债和改进方向

实用、可操作，提供具体代码示例。`, {
      label: '开发者指南'
    });

    fs.writeFileSync('docs/DEVELOPER-GUIDE.md', devGuide);
    return 'DEVELOPER-GUIDE.md';
  },

  // 5. 知识图谱JSON
  async () => {
    const knowledgeGraph = {
      metadata: {
        project: 'OpenCoreAnalysisKit',
        version: '1.0',
        generatedAt: new Date().toISOString(),
        totalLayers: layersData.length,
        totalFiles: scanData.length
      },
      layers: validAnalyses,
      crossLayerRelations: crossLayerAnalysis,
      learningPath: tourData,
      index: {
        apisByLayer: validAnalyses.reduce((acc, layer) => {
          acc[layer.layerId] = layer.publicAPIs.map(api => api.interface);
          return acc;
        }, {}),
        dataStructures: validAnalyses.flatMap(layer => 
          layer.keyDataStructures.map(ds => ({
            name: ds.name,
            layer: layer.layerId,
            purpose: ds.purpose
          }))
        ),
        designPatterns: validAnalyses.flatMap(layer =>
          layer.designPatterns.map(p => ({
            pattern: p.pattern,
            layer: layer.layerId,
            application: p.application
          }))
        )
      }
    };

    fs.writeFileSync('.understand-anything/knowledge-graph.json',
      JSON.stringify(knowledgeGraph, null, 2));

    return 'knowledge-graph.json';
  }
]);

const validProducts = knowledgeProducts.filter(Boolean);
log(`✅ 生成${validProducts.length}个知识产物`);

// 生成总结报告
const summary = `# OpenCoreAnalysisKit 深度探索报告

## 📊 分析统计

- **架构层数**：${layersData.length}个
- **深度分析层**：${validAnalyses.length}个
- **核心组件**：${validAnalyses.reduce((sum, a) => sum + a.coreComponents.length, 0)}个
- **公共API**：${validAnalyses.reduce((sum, a) => sum + a.publicAPIs.length, 0)}个
- **关键数据结构**：${validAnalyses.reduce((sum, a) => sum + a.keyDataStructures.length, 0)}个
- **设计模式**：${validAnalyses.reduce((sum, a) => sum + a.designPatterns.length, 0)}个
- **跨层交互**：${crossLayerAnalysis.interactions.length}个
- **数据流路径**：${crossLayerAnalysis.dataFlows.length}条

## 📚 生成的知识产物

${validProducts.map(p => `- ${p}`).join('\n')}

## 🎯 核心发现

### 架构层次
${validAnalyses.slice(0, 5).map(a => `
#### ${a.layerName}
- 核心组件：${a.coreComponents.length}个
- 公共API：${a.publicAPIs.length}个
- 关键数据结构：${a.keyDataStructures.length}个
`).join('\n')}

### 关键数据流
${crossLayerAnalysis.dataFlows.slice(0, 3).map(df => `
- **${df.flowName}**: ${df.path.join(' → ')}
`).join('\n')}

## 🔍 使用指南

1. **查阅API** → \`docs/API-REFERENCE.md\`
2. **理解架构** → \`docs/ARCHITECTURE-OVERVIEW.md\`
3. **追踪数据流** → \`docs/DATA-FLOWS.md\`
4. **快速上手** → \`docs/DEVELOPER-GUIDE.md\`
5. **查询知识图谱** → \`.understand-anything/knowledge-graph.json\`

## 📈 下一步

- 使用知识图谱进行智能代码导航
- 基于API文档生成代码补全
- 基于数据流优化性能热点
- 基于设计模式识别重构机会
`;

fs.writeFileSync('docs/DEEP-EXPLORATION-REPORT.md', summary);

log(`\n🎉 深度探索完成！`);
log(`📁 知识图谱：.understand-anything/knowledge-graph.json`);
log(`📚 文档产物：docs/目录下${validProducts.length}个文件`);
log(`📊 总结报告：docs/DEEP-EXPLORATION-REPORT.md`);

return {
  layersAnalyzed: validAnalyses.length,
  componentsFound: validAnalyses.reduce((sum, a) => sum + a.coreComponents.length, 0),
  apisExtracted: validAnalyses.reduce((sum, a) => sum + a.publicAPIs.length, 0),
  dataFlows: crossLayerAnalysis.dataFlows.length,
  documentsGenerated: validProducts.length
};

export const meta = {
  name: 'deep-parallel-exploration',
  description: '高性能并行探索OpenCoreAnalysisKit并生成结构化知识库',
  phases: [
    { title: '并行层分析', detail: '11层并行深度分析核心实现' },
    { title: '知识提取', detail: '提取API、数据结构、设计模式' },
    { title: '结构化输出', detail: '生成知识图谱和查询索引' }
  ]
}

const fs = require('fs');

// 加载已有分析结果
const layersData = JSON.parse(fs.readFileSync('.understand-anything/intermediate/layers.json', 'utf8'));
const tourData = JSON.parse(fs.readFileSync('.understand-anything/intermediate/tour.json', 'utf8'));

log(`📊 加载完成: ${layersData.length}个架构层`);

// 简化的分析schema
const LayerInsightSchema = {
  type: 'object',
  required: ['layerId', 'keyComponents', 'publicAPIs', 'dataStructures', 'usagePatterns'],
  properties: {
    layerId: { type: 'string' },
    keyComponents: {
      type: 'array',
      items: {
        type: 'object',
        required: ['name', 'file', 'purpose', 'keyMethods'],
        properties: {
          name: { type: 'string' },
          file: { type: 'string' },
          purpose: { type: 'string' },
          keyMethods: { type: 'array', items: { type: 'string' } }
        }
      }
    },
    publicAPIs: {
      type: 'array',
      items: {
        type: 'object',
        required: ['signature', 'description'],
        properties: {
          signature: { type: 'string' },
          description: { type: 'string' },
          example: { type: 'string' }
        }
      }
    },
    dataStructures: {
      type: 'array',
      items: {
        type: 'object',
        required: ['name', 'purpose', 'keyFields'],
        properties: {
          name: { type: 'string' },
          purpose: { type: 'string' },
          keyFields: { type: 'array', items: { type: 'string' } }
        }
      }
    },
    usagePatterns: {
      type: 'array',
      items: {
        type: 'object',
        required: ['scenario', 'steps'],
        properties: {
          scenario: { type: 'string' },
          steps: { type: 'array', items: { type: 'string' } }
        }
      }
    }
  }
};

// Phase 1: 并行分析各层（使用pipeline避免barrier）
phase('并行层分析');

log(`🚀 启动${layersData.length}个层的并行分析`);

const insights = await pipeline(
  layersData,

  // 深度分析单个层
  async (layer, idx) => {
    // 选择核心文件（最多8个）
    const coreFiles = layer.nodeIds
      .filter(id => id.startsWith('file:'))
      .map(id => id.replace('file:', ''))
      .filter(f => 
        f.endsWith('.cpp') || f.endsWith('.h')
      )
      .slice(0, 8);

    const prompt = `深度分析架构层: ${layer.name}

描述: ${layer.description}

核心文件:
${coreFiles.join('\n')}

请分析:
1. 关键组件: 该层的核心类/结构体及其职责
2. 公共API: 暴露给其他层的接口（函数签名、参数、返回值）
3. 数据结构: 重要的数据结构、内存布局、字段含义
4. 使用模式: 典型使用场景和代码流程

要求:
- 聚焦最核心的3-5个组件
- API要包含具体的C++函数签名
- 数据结构说明关键字段的作用
- 使用模式要描述完整的调用链

提供具体代码片段和示例。`;

    return await agent(prompt, {
      label: layer.name.substring(0, 30),
      phase: '并行层分析',
      schema: LayerInsightSchema
    });
  }
);

const validInsights = insights.filter(Boolean);
log(`✅ 完成${validInsights.length}层分析`);

// 保存中间结果
fs.writeFileSync('.understand-anything/intermediate/layer-insights.json',
  JSON.stringify(validInsights, null, 2));

// Phase 2: 知识提取
phase('知识提取');

// 并行提取不同维度的知识
const [apiIndex, dataStructIndex, patternIndex] = await parallel([

  // 1. API索引
  async () => {
    log('提取API索引...');
    const allAPIs = validInsights.flatMap(insight => 
      insight.publicAPIs.map(api => ({
        layer: insight.layerId,
        signature: api.signature,
        description: api.description,
        example: api.example
      }))
    );

    const apiByCategory = {
      coreLoading: allAPIs.filter(a => 
        a.signature.includes('Load') || a.signature.includes('Parse') || a.signature.includes('Read')
      ),
      memoryAccess: allAPIs.filter(a =>
        a.signature.includes('Memory') || a.signature.includes('VirtualAddr') || a.signature.includes('Read')
      ),
      objectInspection: allAPIs.filter(a =>
        a.signature.includes('Object') || a.signature.includes('Class') || a.signature.includes('GetField')
      ),
      threadAnalysis: allAPIs.filter(a =>
        a.signature.includes('Thread') || a.signature.includes('Stack') || a.signature.includes('Frame')
      ),
      commandSystem: allAPIs.filter(a =>
        a.signature.includes('Command') || a.signature.includes('Register') || a.signature.includes('Execute')
      )
    };

    return { totalAPIs: allAPIs.length, byCategory: apiByCategory };
  },

  // 2. 数据结构索引
  async () => {
    log('构建数据结构索引...');
    const allStructs = validInsights.flatMap(insight =>
      insight.dataStructures.map(ds => ({
        layer: insight.layerId,
        name: ds.name,
        purpose: ds.purpose,
        keyFields: ds.keyFields
      }))
    );

    return {
      totalStructures: allStructs.length,
      structures: allStructs,
      byType: {
        artMirror: allStructs.filter(s => s.name.includes('mirror::')),
        coreTypes: allStructs.filter(s => s.name.includes('Core') || s.name.includes('ELF')),
        gcTypes: allStructs.filter(s => s.name.includes('Space') || s.name.includes('Heap')),
        threadTypes: allStructs.filter(s => s.name.includes('Thread') || s.name.includes('Stack'))
      }
    };
  },

  // 3. 使用模式索引
  async () => {
    log('提取使用模式...');
    const allPatterns = validInsights.flatMap(insight =>
      insight.usagePatterns.map(p => ({
        layer: insight.layerId,
        scenario: p.scenario,
        steps: p.steps
      }))
    );

    return {
      totalPatterns: allPatterns.length,
      patterns: allPatterns
    };
  }
]);

log(`✅ 提取完成: ${apiIndex.totalAPIs}个API, ${dataStructIndex.totalStructures}个数据结构, ${patternIndex.totalPatterns}个模式`);

// Phase 3: 生成结构化输出
phase('结构化输出');

log('📚 生成知识产物...');

// 并行生成文档
const docs = await parallel([

  // API速查手册
  async () => {
    const content = await agent(`生成API速查手册 (Markdown格式):

API分类:
- Core加载: ${apiIndex.byCategory.coreLoading.length}个
- 内存访问: ${apiIndex.byCategory.memoryAccess.length}个
- 对象检查: ${apiIndex.byCategory.objectInspection.length}个
- 线程分析: ${apiIndex.byCategory.threadAnalysis.length}个
- 命令系统: ${apiIndex.byCategory.commandSystem.length}个

详细API列表:
${JSON.stringify(apiIndex.byCategory, null, 2)}

生成包含:
1. 按功能分类的API列表
2. 每个API的签名、参数说明、返回值
3. 使用示例代码
4. 常见用法和注意事项

格式清晰，代码示例可运行。`, { label: 'API手册' });

    fs.writeFileSync('docs/API-QUICK-REFERENCE.md', content);
    return 'API-QUICK-REFERENCE.md';
  },

  // 数据结构手册
  async () => {
    const content = await agent(`生成数据结构手册 (Markdown格式):

数据结构分类:
- ART Mirror对象: ${dataStructIndex.byType.artMirror.length}个
- Core类型: ${dataStructIndex.byType.coreTypes.length}个
- GC类型: ${dataStructIndex.byType.gcTypes.length}个
- Thread类型: ${dataStructIndex.byType.threadTypes.length}个

详细结构列表:
${JSON.stringify(dataStructIndex.structures.slice(0, 30), null, 2)}

生成包含:
1. 每个数据结构的内存布局
2. 关键字段的含义和大小
3. 对齐要求和padding
4. 访问示例代码

重点说明ART Mirror对象的HeapReference压缩引用机制。`, { label: '数据结构手册' });

    fs.writeFileSync('docs/DATA-STRUCTURES.md', content);
    return 'DATA-STRUCTURES.md';
  },

  // 使用模式cookbook
  async () => {
    const content = await agent(`生成使用模式Cookbook (Markdown格式):

使用模式:
${JSON.stringify(patternIndex.patterns.slice(0, 20), null, 2)}

生成cookbook包含:
1. 常见任务的完整代码示例
2. 最佳实践和性能优化
3. 错误处理和边界情况
4. 调试技巧

重点场景:
- 加载并解析coredump
- 遍历Java堆找特定对象
- 解析线程调用栈
- 添加新的REPL命令
- 适配新的Android版本

每个场景都要完整的可运行代码。`, { label: 'Cookbook' });

    fs.writeFileSync('docs/USAGE-COOKBOOK.md', content);
    return 'USAGE-COOKBOOK.md';
  },

  // 架构地图
  async () => {
    const content = await agent(`生成架构地图文档 (Markdown + Mermaid):

架构层:
${layersData.map((l, i) => `${i+1}. ${l.name}`).join('\n')}

组件统计:
${validInsights.map(i => `- ${i.layerId}: ${i.keyComponents.length}个组件, ${i.publicAPIs.length}个API`).join('\n')}

生成:
1. 架构层次图 (Mermaid diagram)
2. 各层的职责和边界
3. 层间调用关系图
4. 关键执行路径图 (coredump加载、堆遍历、栈回溯)
5. 扩展点说明

使用Mermaid绘制清晰的架构图。`, { label: '架构地图' });

    fs.writeFileSync('docs/ARCHITECTURE-MAP.md', content);
    return 'ARCHITECTURE-MAP.md';
  }
]);

const validDocs = docs.filter(Boolean);
log(`✅ 生成${validDocs.length}个文档`);

// 构建知识图谱
const knowledgeGraph = {
  meta: {
    project: 'OpenCoreAnalysisKit',
    totalLayers: layersData.length,
    analyzedLayers: validInsights.length,
    timestamp: '2026-06-06' // 使用固定日期保证确定性
  },
  layers: validInsights,
  indexes: {
    apis: apiIndex,
    dataStructures: dataStructIndex,
    patterns: patternIndex
  },
  tour: tourData,
  quickAccess: {
    allAPIs: apiIndex.byCategory,
    coreStructures: dataStructIndex.byType,
    commonPatterns: patternIndex.patterns.slice(0, 10)
  }
};

fs.writeFileSync('.understand-anything/knowledge-graph.json',
  JSON.stringify(knowledgeGraph, null, 2));

// 生成索引文件
const indexContent = `# OpenCoreAnalysisKit 知识库索引

## 📊 统计

- 架构层: ${validInsights.length}
- 核心组件: ${validInsights.reduce((s, i) => s + i.keyComponents.length, 0)}
- 公共API: ${apiIndex.totalAPIs}
- 数据结构: ${dataStructIndex.totalStructures}
- 使用模式: ${patternIndex.totalPatterns}

## 📚 文档

${validDocs.map(d => `- [${d}](${d})`).join('\n')}

## 🗂️ 快速查找

### API分类
- Core加载: ${apiIndex.byCategory.coreLoading.length}个
- 内存访问: ${apiIndex.byCategory.memoryAccess.length}个
- 对象检查: ${apiIndex.byCategory.objectInspection.length}个
- 线程分析: ${apiIndex.byCategory.threadAnalysis.length}个
- 命令系统: ${apiIndex.byCategory.commandSystem.length}个

### 数据结构分类
- ART Mirror: ${dataStructIndex.byType.artMirror.length}个
- Core类型: ${dataStructIndex.byType.coreTypes.length}个
- GC类型: ${dataStructIndex.byType.gcTypes.length}个
- Thread类型: ${dataStructIndex.byType.threadTypes.length}个

## 🔍 使用方式

1. **查API** → docs/API-QUICK-REFERENCE.md
2. **查数据结构** → docs/DATA-STRUCTURES.md
3. **学习用法** → docs/USAGE-COOKBOOK.md
4. **理解架构** → docs/ARCHITECTURE-MAP.md
5. **程序化查询** → .understand-anything/knowledge-graph.json

## 📖 学习路径

按照以下顺序学习效果最佳:
${tourData.slice(0, 5).map((t, i) => `${i+1}. ${t.title}`).join('\n')}

完整学习路径见 knowledge-graph.json 的 tour 字段。
`;

fs.writeFileSync('docs/KNOWLEDGE-INDEX.md', indexContent);

log('\n🎉 知识库构建完成!');
log(`📁 知识图谱: .understand-anything/knowledge-graph.json`);
log(`📚 文档产物: ${validDocs.join(', ')}`);
log(`📖 索引: docs/KNOWLEDGE-INDEX.md`);

return {
  success: true,
  layersAnalyzed: validInsights.length,
  apisExtracted: apiIndex.totalAPIs,
  structuresFound: dataStructIndex.totalStructures,
  patternsIdentified: patternIndex.totalPatterns,
  documentsGenerated: validDocs.length
};

